{
  "sentences": [
    {
      "text": "我要一個飯糰和一杯咖啡。",
      "pinyin": "Wǒ yào yī gè fàntuán hé yī bēi kāfēi.",
      "pinyin_numeric": "wo3 yao4 yi1 ge4 fan4tuan2 he2 yi1 bei1 ka1fei1",
      "translation_en": "I want one rice ball and one cup of coffee.",
      "translation_ko": "주먹밥 하나와 커피 한 잔을 원해요."
    },
    {
      "text": "這個便當需要加熱嗎？",
      "pinyin": "Zhège biàndāng xūyào jiārè ma?",
      "pinyin_numeric": "zhe4ge5 bian4dang1 xu1yao4 jia1re4 ma0",
      "translation_en": "Does this bento need to be heated?",
      "translation_ko": "이 도시락은 데워야 하나요?"
    },
    {
      "text": "我要買一個環保袋。",
      "pinyin": "Wǒ yào mǎi yī gè huánbǎo dài.",
      "pinyin_numeric": "wo3 yao4 mai3 yi1 ge4 huan2bao3 dai4",
      "translation_en": "I want to buy one eco-friendly bag.",
      "translation_ko": "친환경 봉투 하나를 살게요."
    },
    {
      "text": "請幫我掃描這個條碼。",
      "pinyin": "Qǐng bāng wǒ sǎomiáo zhège tiáomǎ.",
      "pinyin_numeric": "qing3 bang1 wo3 sao3miao2 zhe4ge5 tiao2ma3",
      "translation_en": "Please scan this barcode for me.",
      "translation_ko": "이 바코드를 스캔해 주세요."
    },
    {
      "text": "我要用信用卡付款。",
      "pinyin": "Wǒ yào yòng xìnyòngkǎ fùkuǎn.",
      "pinyin_numeric": "wo3 yao4 yong4 xin4yong4ka3 fu4kuan3",
      "translation_en": "I want to pay with a credit card.",
      "translation_ko": "신용카드로 결제할게요."
    },
    {
      "text": "這個三明治有特價嗎？",
      "pinyin": "Zhège sānmíngzhì yǒu tèjià ma?",
      "pinyin_numeric": "zhe4ge5 san1ming2zhi4 you3 te4jia4 ma0",
      "translation_en": "Is this sandwich on sale?",
      "translation_ko": "이 샌드위치는 특가인가요?"
    },
    {
      "text": "我要買一包餅乾和一瓶礦泉水。",
      "pinyin": "Wǒ yào mǎi yī bāo bǐnggān hé yī píng kuàngquánshuǐ.",
      "pinyin_numeric": "wo3 yao4 mai3 yi1 bao1 bing3gan1 he2 yi1 ping2 kuang4quan2shui3",
      "translation_en": "I want to buy one pack of cookies and one bottle of mineral water.",
      "translation_ko": "과자 한 봉지와 생수 한 병을 살게요."
    },
    {
      "text": "總共是兩百三十塊。",
      "pinyin": "Zǒnggòng shì liǎng bǎi sānshí kuài.",
      "pinyin_numeric": "zong3gong4 shi4 liang3 bai3 san1shi2 kuai4",
      "translation_en": "The total is 230 dollars.",
      "translation_ko": "총 230원입니다."
    },
    {
      "text": "我要用載具存發票。",
      "pinyin": "Wǒ yào yòng zàijù cún fāpiào.",
      "pinyin_numeric": "wo3 yao4 yong4 zai4ju4 cun2 fa1piao4",
      "translation_en": "I want to store the receipt using the carrier.",
      "translation_ko": "영수증을 클라우드에 저장할게요."
    },
    {
      "text": "這個茶葉蛋買一送一嗎？",
      "pinyin": "Zhège cháyèdàn mǎi yī sòng yī ma?",
      "pinyin_numeric": "zhe4ge5 cha2ye4dan4 mai3 yi1 song4 yi1 ma0",
      "translation_en": "Is this tea egg buy one get one free?",
      "translation_ko": "이 차(tea) 달걀은 하나 사면 하나 더 주나요?"
    }
  ]
}
